parameters.jsCode:
const body = $input.item.json.body;

const capitalizarNombre = (str) =>
  str.trim().toLowerCase().replace(/\b\w/g, c => c.toUpperCase());

const normalizarTelefono = (str) =>
  str.trim().replace(/[\s\-().]/g, '');

return {
  json: {
    body: {
      nombre:   capitalizarNombre(body.nombre),
      correo:   body.correo.trim().toLowerCase(),
      telefono: normalizarTelefono(body.telefono)
    }
  }
};

parameters.query:
query buscarCliente($query: String!) {
  customers(first: 1, query: $query) {
    edges {
      node {
        id
        email
      }
    }
  }
}

parameters.jsCode:
// Rama: cliente YA existía en Shopify
const gid = $input.item.json.data.customers.edges[0].node.id;
const numericId = gid.split('/').pop();

return {
  json: {
    customer: { id: numericId }
  }
};

// Rama: cliente recién creado en Shopify
// El HTTP Request devuelve customer.id como número directamente
const numericId = String($input.item.json.customer.id);

return {
  json: {
    customer: { id: numericId }
  }
};

